$addButtonSeason=document.getElementById("seasonAddCollection");if($addButtonSeason){let $blockCollectionCall=document.getElementById("collection-season");if($blockCollectionCall){$addButtonSeason.addEventListener("click",(function(){let $addButtonSeason=this;let newForm=$addButtonSeason.dataset.prototype;let index=$addButtonSeason.dataset.index*1;newForm=newForm.replace(/__seasons__/g,index);let div=document.createElement("div");div.id="product_form_project_season_"+index;div.classList.add("mb-3");div.classList.add("item-season");div.innerHTML=newForm;$blockCollectionCall.append(div);div.querySelector(".del-item-season")?.addEventListener("click",deleteSeason);const delButton=div.querySelector(".del-item-season");delButton.dataset.delete="product_form_project_season_"+index.toString();$addButtonSeason.dataset.index=(index+1).toString();div.scrollIntoView({block:"center",inline:"center",behavior:"smooth"})}))}}document.querySelectorAll(".del-item-season").forEach((function(item){item.addEventListener("click",deleteSeason)}));function deleteSeason(){let seasons=document.querySelectorAll(".item-season").length;document.getElementById(this.dataset.delete).remove()}